using UnityEngine;

/// <summary>
/// Resolve referências a NPCs por "Npc Id" (Etapa 8 — ver NpcController.npcId),
/// como alternativa a arrastar uma referência directa de Transform no Inspector.
/// Usado por ações que apontam para outro NPC (ex: olhar para, mover para).
/// </summary>
public static class NpcRefUtil
{
    /// <summary>
    /// Se "npcId" estiver definido e existir um NPC activo com esse ID, devolve
    /// o seu Transform. Caso contrário devolve "fallback" (a referência directa
    /// configurada no Inspector).
    /// </summary>
    public static Transform Resolve(string npcId, Transform fallback)
    {
        if (!string.IsNullOrEmpty(npcId))
        {
            var npc = NpcController.FindById(npcId);
            if (npc != null) return npc.transform;
        }

        return fallback;
    }
}
